// WHY runOnceForAllItems: WooCommerce returns N order items.
// We need ONE aggregated report object, not N separate outputs.
// If this ran per-item, we'd get N identical rows in Google Sheets.

const orders = $input.all();

// --- Accumulators ---
let totalSales = 0;
const productMap = {};  // { 'Product Name': totalQty }
const statusBreakdown = {};  // { 'completed': 3, 'processing': 1 }

// --- Loop through all WooCommerce order objects ---
for (const item of orders) {
  const order = item.json;

  // WooCommerce returns total as a STRING like "89.99" — parseFloat required
  totalSales += parseFloat(order.total || 0);

  // Group orders by status (completed, processing, cancelled, on-hold, etc.)
  const status = order.status || 'unknown';
  statusBreakdown[status] = (statusBreakdown[status] || 0) + 1;

  // Sum product quantities across all line items in this order
  // order.line_items is an array of { name, quantity, ... }
  for (const lineItem of (order.line_items || [])) {
    const name = lineItem.name || 'Unknown Product';
    productMap[name] = (productMap[name] || 0) + parseInt(lineItem.quantity || 1);
  }
}

// --- Top 5 products by units sold, descending ---
const topProducts = Object.entries(productMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, qty]) => `${name} (${qty})`)
  .join(', ');

// --- Human-readable status breakdown ---
const statusText = Object.entries(statusBreakdown)
  .map(([k, v]) => `${k}: ${v}`)
  .join(' | ');

// --- Report date = yesterday (the day whose orders we just fetched) ---
const today = new Date();
const yesterday = new Date(today);
yesterday.setDate(yesterday.getDate() - 1);
const reportDate = yesterday.toISOString().split('T')[0]; // format: YYYY-MM-DD

// --- Final output: single item with all metrics ---
return [{
  json: {
    report_date: reportDate,
    total_sales: parseFloat(totalSales.toFixed(2)),
    order_count: orders.length,
    top_products: topProducts || 'No orders today',
    status_breakdown: statusText || 'No orders today',
    currency: orders[0]?.json?.currency || 'USD'
  }
}];

